9247 bool BoUpSLP::isTreeTinyAndNotFullyVectorizable(bool ForReduction) const {
9248   // No need to vectorize inserts of gathered values.
9249   if (VectorizableTree.size() == 2 &&
9250       isa<InsertElementInst>(VectorizableTree[0]->Scalars[0]) &&
9251       VectorizableTree[1]->State == TreeEntry::NeedToGather &&
9252       (VectorizableTree[1]->getVectorFactor() <= 2 ||
9253        !(isSplat(VectorizableTree[1]->Scalars) ||
9254          allConstant(VectorizableTree[1]->Scalars))))
9255     return true;
9256 
9257   // If the graph includes only PHI nodes and gathers, it is defnitely not
9258   // profitable for the vectorization, we can skip it, if the cost threshold is
9259   // default. The cost of vectorized PHI nodes is almost always 0 + the cost of
9260   // gathers/buildvectors.
9261   constexpr int Limit = 4;
9262   if (!ForReduction && !SLPCostThreshold.getNumOccurrences() &&
9263       !VectorizableTree.empty() &&
9264       all_of(VectorizableTree, [&](const std::unique_ptr<TreeEntry> &TE) {
9265         return (TE->State == TreeEntry::NeedToGather &&
9266                 TE->getOpcode() != Instruction::ExtractElement &&
9267                 count_if(TE->Scalars, IsaPred<ExtractElementInst>) <= Limit) ||
9268                TE->getOpcode() == Instruction::PHI;
9269       }))
9270     return true;
9271 
9272   // We can vectorize the tree if its size is greater than or equal to the
9273   // minimum size specified by the MinTreeSize command line option.
9274   if (VectorizableTree.size() >= MinTreeSize)
9275     return false;
9276 
9277   // If we have a tiny tree (a tree whose size is less than MinTreeSize), we
9278   // can vectorize it if we can prove it fully vectorizable.
9279   if (isFullyVectorizableTinyTree(ForReduction))
9280     return false;
9281 
9282   // Check if any of the gather node forms an insertelement buildvector
9283   // somewhere.
9284   bool IsAllowedSingleBVNode =
9285       VectorizableTree.size() > 1 ||
9286       (VectorizableTree.size() == 1 && VectorizableTree.front()->getOpcode() &&
9287        VectorizableTree.front()->getOpcode() != Instruction::PHI &&
9288        VectorizableTree.front()->getOpcode() != Instruction::GetElementPtr &&
9289        allSameBlock(VectorizableTree.front()->Scalars));
9290   if (any_of(VectorizableTree, [&](const std::unique_ptr<TreeEntry> &TE) {
9291         return TE->State == TreeEntry::NeedToGather &&
9292                all_of(TE->Scalars, [&](Value *V) {
9293                  return isa<ExtractElementInst, UndefValue>(V) ||
9294                         (IsAllowedSingleBVNode &&
9295                          !V->hasNUsesOrMore(UsesLimit) &&
9296                          any_of(V->users(), IsaPred<InsertElementInst>));
9297                });
9298       }))
9299     return false;
9300 
9301   assert(VectorizableTree.empty()
9302              ? ExternalUses.empty()
9303              : true && "We shouldn't have any external users");
9304 
9305   // Otherwise, we can't vectorize the tree. It is both tiny and not fully
9306   // vectorizable.
9307   return true;
9308 }
